python -m docker_entrypoint \
    --model bpnet \
        --protein 'GATA2' \
    --optimization adabeam \
        --beam_size 2 \
        --n_rollouts_per_root 4 \
        --mutations_per_sequence 2 \
        --rng_seed 0 \
    --max_seconds 240 \
    --optimization_steps_per_output 5 \
    --proposals_per_round 2 \
    --output_format csv \
    --output_path ./output/python_recipe/adabeam_gata2 \
    --start_sequence 
